let rawData = $input.first().json;
let data;
try {
  const text = typeof rawData === "string" ? rawData : (rawData.data || JSON.stringify(rawData));
  if (typeof text === "string" && text.includes("limit requests")) return [{ json: { skip: true, events: [], reason: "rate_limited" } }];
  data = typeof text === "string" ? JSON.parse(text) : rawData;
} catch(e) {
  return [{ json: { skip: true, events: [], reason: "parse_error" } }];
}
const articles = data.articles || [];
if (!articles.length) return [{ json: { skip: true, events: [] } }];

// Keyword impact mapping
const impactMap = {
  'sanctions': { impact: 'high', type: 'sanctions', assets: ['GOLD','OIL','USD'] },
  'tariff': { impact: 'high', type: 'trade_war', assets: ['SPY','COPPER','USD'] },
  'trade war': { impact: 'high', type: 'trade_war', assets: ['SPY','COPPER','GOLD'] },
  'OPEC': { impact: 'high', type: 'policy_change', assets: ['OIL','NATGAS'] },
  'interest rate': { impact: 'medium', type: 'policy_change', assets: ['GOLD','TLT','USD'] },
  'central bank': { impact: 'medium', type: 'policy_change', assets: ['GOLD','TLT','SPY'] },
  'military': { impact: 'critical', type: 'conflict', assets: ['GOLD','OIL','USD'] },
  'embargo': { impact: 'high', type: 'sanctions', assets: ['OIL','NATGAS','GOLD'] },
  'nuclear': { impact: 'critical', type: 'conflict', assets: ['GOLD','OIL','USD'] },
  'invasion': { impact: 'critical', type: 'conflict', assets: ['GOLD','OIL','NATGAS'] }
};

const events = [];
const seen = new Set();

for (const art of articles) {
  const title = (art.title || '').toLowerCase();
  if (seen.has(title)) continue;
  seen.add(title);

  let bestMatch = { impact: 'low', type: 'general', assets: [] };
  for (const [keyword, info] of Object.entries(impactMap)) {
    if (title.includes(keyword.toLowerCase())) {
      if (['critical','high'].includes(info.impact)) {
        bestMatch = info;
        break;
      }
      if (info.impact === 'medium' && bestMatch.impact === 'low') bestMatch = info;
    }
  }

  // Simple sentiment from tone
  const tone = parseFloat(art.tone) || 0;
  const sentiment = Math.round(Math.max(-100, Math.min(100, tone * 10)));

  events.push({
    event_type: bestMatch.type,
    description: art.title || 'No title',
    sentiment_score: sentiment,
    affected_assets: bestMatch.assets,
    source: 'gdelt',
    impact_level: bestMatch.impact
  });
}

// Filter: only medium+ impact
const significant = events.filter(e => e.impact_level !== 'low');

return [{ json: { events: significant, total: articles.length, significant_count: significant.length, skip: significant.length === 0 } }];

const data = $('Analyze Events').first().json;
const events = data.events || [];
const results = [];
for (const e of events) {
  results.push({ json: { ...e, affected_assets: `{${e.affected_assets.join(',')}}`, timestamp: new Date().toISOString() } });
}
return results;

const data = $('Analyze Events').first().json;
const critical = data.events.filter(e => e.impact_level === 'critical' || e.impact_level === 'high');
if (!critical.length) return [{ json: { skip: true } }];

const lines = critical.slice(0, 5).map(e => {
  const emoji = e.impact_level === 'critical' ? '\ud83d\udea8' : '\u26a0\ufe0f';
  return `${emoji} *${e.event_type.toUpperCase()}*\n${e.description}\nAffects: ${e.affected_assets.join(', ')} | Sentiment: ${e.sentiment_score}`;
}).join('\n\n');

return [{ json: { message: `\ud83c\udf0d *Geopolitical Alert*\n\n${lines}`, skip: false } }];

